<style scoped>
.animation-box {
  --brand-base: #6F8A4A;
  /* Brand 500 */
  --brand-dark: #465B30;
  /* Brand 700 */

  /* Scoped Animation Variables */
  --bounce-duration: 0.9s;
  --bounce-height: -20px;

  display: flex;
  justify-content: center;
  flex-wrap: wrap;
  font-family: 'Roboto', sans-serif;
  font-weight: 900;
  font-size: 60px;
  color: var(--brand-base);

  @media (max-width: 580px) {
    font-size: 30px;
  }

   @media (max-width: 300px) {
    font-size: 20px;
  }
}


.animation-box span {
  display: inline-block;
  transform: translateY(20px);
  will-change: transform;
  animation: bounce var(--bounce-duration) ease infinite alternate;

}

@keyframes bounce {
  100% {
    /* Using the scoped variable for jump height */
    transform: translateY(var(--bounce-height));
  }
}

@media (prefers-reduced-motion: reduce) {
  .animation-box span {
    animation: none;
    transform: translateY(0);
  }
}

/* CSS-Only Delays: Smooth 0.05s increments */
.animation-box span:nth-child(1) {
  animation-delay: 0.00s;
}

.animation-box span:nth-child(2) {
  animation-delay: 0.05s;
}

.animation-box span:nth-child(3) {
  animation-delay: 0.10s;
}

.animation-box span:nth-child(4) {
  animation-delay: 0.15s;
}

.animation-box span:nth-child(5) {
  animation-delay: 0.20s;
}

.animation-box span:nth-child(6) {
  animation-delay: 0.25s;
}

.animation-box span:nth-child(7) {
  animation-delay: 0.30s;
}

/* Space */
.animation-box span:nth-child(8) {
  animation-delay: 0.35s;
}

.animation-box span:nth-child(9) {
  animation-delay: 0.40s;
}

.animation-box span:nth-child(10) {
  animation-delay: 0.45s;
}

/* Space */
.animation-box span:nth-child(11) {
  animation-delay: 0.50s;
}

.animation-box span:nth-child(12) {
  animation-delay: 0.55s;
}

.animation-box span:nth-child(13) {
  animation-delay: 0.60s;
}

.animation-box span:nth-child(14) {
  animation-delay: 0.65s;
}

.animation-box span:nth-child(15) {
  animation-delay: 0.70s;
}

.animation-box span:nth-child(16) {
  animation-delay: 0.75s;
}

.animation-box span:nth-child(17) {
  animation-delay: 0.80s;
}

.animation-box span:nth-child(18) {
  animation-delay: 0.85s;
}

.animation-box span:nth-child(19) {
  animation-delay: 0.90s;
}

.jumping-man {
  width: 240px;
  transform: rotate(180deg) translateY(62px);

  @media (max-width: 580px) {
    margin-left: 10px;
  }

  @media (max-width: 615px) {
    transform: rotate(180deg) translateY(-20px);
    margin-bottom: 50px;
  }

  @media (min-width: 615px) and (max-width: 820px) {
    transform: rotate(180deg) translateY(-40px);
    margin-bottom: 50px;
  }
}
</style>